	&lt;li&gt;&lt;span style=&quot;&quot;&gt;B sits second to the right of A. &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;B is&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;not an immediate neighbour of C&lt;/span&gt;&lt;/li&gt;
